    '[{"id":"e1","name":"소셜 엔지니어링","desc":"필살기를 발동해 적 공격 후 목표가 보유한 <u>디버프 효과</u> 1개당 은랑은 에너지를 <unbreak>#1[i]</unbreak>pt 회복한다. 해당 효과는 필살기 공격마다 최대 <unbreak>#2[i]</unbreak>회 적용된다","icon":"SkillIcon_1006_Rank1","params":[7,5],"skillAddLevelList":null},{"id":"e2","name":"좀비 네트워크","desc":"적이 전투 진입 시 효과 저항이 <unbreak>#1[i]%</unbreak> 감소한다","icon":"SkillIcon_1006_Rank2","params":[0.2],"skillAddLevelList":null},{"id":"e3","name":"페이로드","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1006_BP","params":null,"skillAddLevelList":{"100602":2,"100604":2}},{"id":"e4","name":"바운스 공격","desc":"필살기를 발동해 적 공격 후 목표가 보유한 <u>디버프 효과</u> 1개당 추가로 은랑 공격력의 <unbreak>#1[i]%</unbreak>만큼 양자 속성 <u>추가 피해</u>를 가한다. 해당 효과는 필살기 공격마다 최대 <unbreak>#2[i]</unbreak>회 발동된다","icon":"SkillIcon_1006_Rank4","params":[0.2,5],"skillAddLevelList":null},{"id":"e5","name":"무차별 대입 공격","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1006_Ultra","params":null,"skillAddLevelList":{"100601":1,"100603":2}},{"id":"e6","name":"오버레이 네트워크","desc":"적이 보유한 <u>디버프 효과</u> 1개당 은랑이 대상에게 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가하며, 최대 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1006_Rank6","params":[0.2,1],"skillAddLevelList":null}]',
