    '[{"id":"e1","name":"필사즉생","desc":"현재 HP 백분율이 <unbreak>50%</unbreak> 이하일 경우 전투 스킬이 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1008_Rank1","params":[0.1],"skillAddLevelList":null},{"id":"e2","name":"구속 해제","desc":"전투 스킬, 필살기 발동 시 자신의 <u>디버프 효과</u>를 1개 해제한다","icon":"SkillIcon_1008_Rank2","params":null,"skillAddLevelList":null},{"id":"e3","name":"강검 공격","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1008_BP","params":null,"skillAddLevelList":{"100801":1,"100802":2}},{"id":"e4","name":"절체절명의 반격","desc":"전투 진입 후 치명적인 공격을 받아도 아를란은 <u>전투 불능 상태</u>에 빠지지 않으며, 즉시 자신 HP 최대치의 <unbreak>#1[i]%</unbreak>까지 회복한다. 해당 효과는 1회 발동 후 또는 <unbreak>#2[i]</unbreak>턴 지속 후 자동으로 해제된다","icon":"SkillIcon_1008_Rank4","params":[0.25,2],"skillAddLevelList":null},{"id":"e5","name":"전력투구","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1008_Ultra","params":null,"skillAddLevelList":{"100803":2,"100804":2}},{"id":"e6","name":"솔선수범","desc":"현재 HP 백분율이 <unbreak>50%</unbreak> 이하일 경우 필살기가 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가하며, 인접한 목표에 대한 피해 배율이 주목표와 같은 피해 배율로 증가한다","icon":"SkillIcon_1008_Rank6","params":[0.2],"skillAddLevelList":null}]',
