ag":null,"maxLevel":1,"skillId":"100907"}]',
    '[{"id":"1009101","name":"불꽃","desc":"일반 공격 발동 시 <unbreak>#1[i]%</unbreak>의 <u>기본 확률</u>로 적을 연소 상태에 빠트린다. 지속 시간: <unbreak>#2[i]</unbreak>턴\\n연소 상태의 적은 턴이 시작될 때마다 아스타 일반 공격의 <unbreak>#3[i]%</unbreak>만큼 화염 속성 지속 피해를 받는다","icon":"SkillIcon_1009_SkillTree1","params":{"1":[0.8],"2":[3],"3":[0.5]},"unlockAscension":2},{"id":"1009102","name":"연소","desc":"아스타가 필드에 있으면 모든 아군이 가하는 화염 속성 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1009_SkillTree2","params":{"1":[0.18]},"unlockAscension":4},{"id":"1009103","name":"별자리","desc":"아스타가 에너지 충전 1스택을 보유할 때마다 자신의 방어력이 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1009_SkillTree3","params":{"1":[0.06]},"unlockAscension":6}]',
