},{"id":"technique","levelKey":"technique","name":"산들바람","formula":"tingyun.technique","icon":"SkillIcon_1202_Maze","params":{"1":[50]},"desc":"비술을 발동하는 즉시 자신의 에너지를 <unbreak>#1[i]</unbreak>pt 회복한다","tag":"서포트","maxLevel":1,"skillId":"120207"}]',
