    '[{"id":"e1","name":"검록의 끝, 지옥변상","desc":"필살기로 지정된 단일 적에게 가하는 피해가 이번 전투에서 누적 손실한 블레이드 HP의 <unbreak>#1[i]%</unbreak>만큼 추가로 증가한다.\\n이번 전투에서 누적 손실한 HP는 블레이드 HP 최대치의 <unbreak>#2[i]%</unbreak>를 넘지 않는다. 필살기 발동 후 리셋하고 다시 누적된다","icon":"SkillIcon_1205_Rank1","params":[1.5,0.9],"skillAddLevelList":null},{"id":"e2","name":"흩어진 옛 꿈, 갖가지 여한","desc":"블레이드가 [지옥변] 상태일 때 치명타 확률이 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1205_Rank2","params":[0.15],"skillAddLevelList":null},{"id":"e3","name":"제련한 현철, 서늘한 빛","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1205_Ultra","params":null,"skillAddLevelList":{"120503":2,"120504":2}},{"id":"e4","name":"황천의 기로, 육신의 회생","desc":"현재 HP 백분율이 <unbreak>50%</unbreak>를 초과한 상태에서 <unbreak>50%</unbreak> 이하로 떨어지면 HP 최대치가 <unbreak>#1[i]%</unbreak> 증가한다. 해당 효과 최대 중첩수: <unbreak>#2[i]</unbreak>스택","icon":"SkillIcon_1205_Rank4","params":[0.2,2],"skillAddLevelList":null},{"id":"e5","name":"시왕의 사형 선고, 마주한 업경","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1205_BP","params":null,"skillAddLevelList":{"120501":1,"120502":2,"120508":1}},{"id":"e6","name":"죽음의 끝, 돌아온 영혼","desc":"충전 스택 수 상한이 4스택으로 감소한다. 특성으로 발동되는 <u>추가 공격</u>으로 가하는 피해가 블레이드 HP 최대치의 <unbreak>#1[i]%</unbreak>만큼 추가로 증가한다","icon":"SkillIcon_1205_Rank6","params":[0.5],"skillAddLevelList":null}]',
