    '[{"id":"1206201","stat":"atkPct","value":0.04,"parentMajor":null,"unlockAscension":0},{"id":"1206202","stat":"hpPct","value":0.04,"parentMajor":"1206101","unlockAscension":2},{"id":"1206203","stat":"atkPct","value":0.04,"parentMajor":"1206101","unlockAscension":3},{"id":"1206204","stat":"defPct","value":0.05,"parentMajor":null,"unlockAscension":3},{"id":"1206205","stat":"atkPct","value":0.06,"parentMajor":"1206102","unlockAscension":4},{"id":"1206206","stat":"hpPct","value":0.06,"parentMajor":"1206102","unlockAscension":5},{"id":"1206207","stat":"atkPct","value":0.06,"parentMajor":null,"unlockAscension":5},{"id":"1206208","stat":"defPct","value":0.075,"parentMajor":"1206103","unlockAscension":6},{"id":"1206209","stat":"hpPct","value":0.08,"parentMajor":"1206103","unlockAscension":6},{"id":"1206210","stat":"atkPct","value":0.08,"parentMajor":"1206103","unlockAscension":6}]',
