    '[{"id":"e1","name":"천관을 범한 달","desc":"필살기 또는 강화된 전투 스킬 발동 시 경류의 치명타 피해가 <unbreak>#1[i]%</unbreak> 증가한다, 지속 시간: <unbreak>#3[i]</unbreak>턴. 적을 1기만 공격하면 해당 목표에게 추가로 경류 공격력의 <unbreak>#2[i]%</unbreak>만큼 얼음 속성 피해를 가한다","icon":"SkillIcon_1212_Rank1","params":[0.24,1,1],"skillAddLevelList":null},{"id":"e2","name":"칠성을 덮은 삭월의 밤","desc":"필살기 발동 후 다음 강화된 전투 스킬의 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1212_Rank2","params":[0.8],"skillAddLevelList":null},{"id":"e3","name":"차오르는 달","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1212_Ultra","params":null,"skillAddLevelList":{"121203":2,"121204":2}},{"id":"e4","name":"달의 검을 쥐고","desc":"[전백(轉魄)] 상태일 때 동료의 HP를 소모해 획득하는 공격력이 추가로 모든 아군 HP 총 소모량의 <unbreak>#1[i]%</unbreak>만큼 증가한다. 획득하는 공격력의 최대치가 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1212_Rank4","params":[0.9,0.3],"skillAddLevelList":null},{"id":"e5","name":"어둠에 잠긴 삼태성","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1212_BP","params":null,"skillAddLevelList":{"121201":1,"121202":2,"121209":2}},{"id":"e6","name":"텅 빈 검은 달","desc":"경류가 [전백(轉魄)] 상태에 진입 시 [삭망]의 최대 스택이 1스택 증가하고 [삭망]을 <unbreak>#1[i]</unbreak>스택 추가로 획득한다. [전백] 상태일 때 치명타 피해가 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1212_Rank6","params":[1,0.5],"skillAddLevelList":null}]',
