    '[{"id":"e1","name":"심마 속박","desc":"특성의 <u>추가 공격</u>으로 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1214_Rank1","params":[0.4],"skillAddLevelList":null},{"id":"e2","name":"오진(五塵) 극복","desc":"특성의 <u>추가 공격</u>이 약점 속성을 무시하고 적의 강인성을 소모시키며, 동시에 설의 HP 최대치의 <unbreak>#1[i]%</unbreak>만큼 HP를 회복한다. 약점 격파 시 양자 속성의 약점 격파 효과가 발동된다","icon":"SkillIcon_1214_Rank2","params":[0.05],"skillAddLevelList":null},{"id":"e3","name":"고제(苦諦) 알절","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1214_BP","params":null,"skillAddLevelList":{"121401":1,"121402":2}},{"id":"e4","name":"악업 단절","desc":"필살기 발동 시 격파 특수효과가 <unbreak>#1[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1214_Rank4","params":[0.4,2],"skillAddLevelList":null},{"id":"e5","name":"영신(靈神) 인도","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1214_Ultra","params":null,"skillAddLevelList":{"121403":2,"121404":2}},{"id":"e6","name":"생사 주관","desc":"[업보]의 스택 수 상한이 <unbreak>#1[i]</unbreak>스택으로 감소한다","icon":"SkillIcon_1214_Rank6","params":[6],"skillAddLevelList":null}]',
