    1701856800000,
    '{"base":{"hp":124.8,"atk":76.8,"def":48},"growth":{"hp":6.24,"atk":3.84,"def":2.4},"ascensionAdd":[{"hp":0,"atk":0,"def":0},{"hp":49.92,"atk":30.72,"def":19.2},{"hp":99.84,"atk":61.44,"def":38.4},{"hp":149.76,"atk":92.16,"def":57.6},{"hp":199.68,"atk":122.88,"def":76.8},{"hp":249.6,"atk":153.6,"def":96},{"hp":299.52,"atk":184.32,"def":115.2}],"spd":110,"taunt":100}',
    '[{"id":"basic","levelKey":"basic","name":"명참천필(冥讖天筆)","formula":"hanya.basic","icon":"SkillIcon_1215_Normal","params":{"1":[0.5,0.6,0.7,0.8,0.9,1,1.1,1.2,1.3,1.4]},"desc":"지정된 단일 적에게 한아 공격력 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼의 물리 속성 피해를 준다","tag":"단일 공격","maxLevel":6,"skillId":"121501"},{"id":"skill","levelKey":"skill","name":"생멸속박","formula":"hanya.skill","icon":"SkillIcon_1215_BP","params":{"1":[1.2,1.32,1.44,1.56,1.68,1.8,1.95,2.1,2.25,2.4,2.52,2.64,2.76,2.88,3],"2":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2]},"desc":"지정된 단일 적에게 한아 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 물리 속성 피해를 주고, [부담] 상태에 빠트린다.\\n아군이 [부담] 상태의 적에게 일반 공격, 전투 스킬, 필살기를 2회 발동할 때마다 즉시 아군의 전투 스킬 포인트를 1pt 회복한다. [부담]은 가장 최근에 부여된 목표에게만 적용되고, 전투 스킬 포인트 회복 효과를 <unbreak>#2[i]</unbreak>회 발동하면 자동으로 해제된다","tag":"단일 공격","maxLevel":10,"skillId":"121502"},{"id":"ultimate","levelKey":"ultimate","name":"시왕의 칙령, 모두 복종하라","formula":"hanya.ultimate","icon":"SkillIcon_1215_Ultra","params":{"1":[0.36,0.384,0.408,0.432,0.456,0.48,0.51,0.54,0.57,0.6,0.624,0.648,0.672,0.696,0.72],"2":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2],"3":[0.15,0.155,0.16,0.165,0.17,0.175,0.18125,0.1875,0.19375,0.2,0.205,0.21,0.215,0.22,0.225]},"desc":"지정된 단일 아군의 속도를 한아 속도의 <color=#f29e38ff><unbreak>#3[f1]%</unbreak></color>만큼 증가시키고, 해당 목표의 공격력을 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color> 증가시킨다. 지속 시간: <unbreak>#2[i]</unbreak>턴","tag":"강화","maxLevel":10,"skillId":"121503"},{"id":"talent","levelKey":"talent","name":"벌악","formula":"hanya.talent","icon":"SkillIcon_1215_Passive","params":{"1":[0.15,0.165,0.18,0.195,0.21,0.225,0.24375,0.2625,0.28125,0.3,0.315,0.33,0.345,0.36,0.375],"2":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2]},"desc":"아군이 [부담] 상태에 빠진 적에게 일반 공격, 전투 스킬, 필살기 발동 시, 가하는 피해가 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","tag":"서포트","maxLevel":10,"skillId":"121504"},{"id":"technique","levelKey":"technique","name":"판명(判冥)","formula":"hanya.technique","icon":"SkillIcon_1215_Maze","params":null,"desc":"적을 바로 공격하며, 전투 진입 후 랜덤 단일 적에게 전투 스킬 효과와 동일한 [부담]을 부여한다","tag":null,"maxLevel":1,"skillId":"121507"}]',
    '[{"id":"1215101","name":"서기","desc":"[부담]의 전투 스킬 포인트 회복 효과를 발동하는 단일 아군의 공격력이 <unbreak>#1[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1215_SkillTree1","params":{"1":[0.1],"2":[1]},"unlockAscension":2},{"id":"1215102","name":"명부","desc":"[부담]을 보유한 적이 처치될 때, [부담] 효과로 모든 파티원의 전투 스킬 포인트 회복을 발동한 횟수가 <unbreak>#1[i]</unbreak>회 이하이면, 추가로 전투 스킬 포인트를 <unbreak>#2[i]</unbreak>pt 회복한다","icon":"SkillIcon_1215_SkillTree2","params":{"1":[1],"2":[1]},"unlockAscension":4},{"id":"1215103","name":"환생","desc":"[부담]의 전투 스킬 포인트 회복 효과가 발동되면 자신의 에너지가 <unbreak>#1[i]</unbreak>pt 회복된다","icon":"SkillIcon_1215_SkillTree3","params":{"1":[2]},"unlockAscension":6}]',
    '[{"id":"1215201","stat":"atkPct","value":0.04,"parentMajor":null,"unlockAscension":0},{"id":"1215202","stat":"spd","value":2,"parentMajor":"1215101","unlockAscension":2},{"id":"1215203","stat":"atkPct","value":0.04,"parentMajor":"1215101","unlockAscension":3},{"id":"1215204","stat":"hpPct","value":0.04,"parentMajor":null,"unlockAscension":3},{"id":"1215205","stat":"atkPct","value":0.06,"parentMajor":"1215102","unlockAscension":4},{"id":"1215206","stat":"spd","value":3,"parentMajor":"1215102","unlockAscension":5},{"id":"1215207","stat":"atkPct","value":0.06,"parentMajor":null,"unlockAscension":5},{"id":"1215208","stat":"hpPct","value":0.06,"parentMajor":"1215103","unlockAscension":6},{"id":"1215209","stat":"spd","value":4,"parentMajor":"1215103","unlockAscension":6},{"id":"1215210","stat":"atkPct","value":0.08,"parentMajor":"1215103","unlockAscension":6}]',
    '[{"id":"e1","name":"일심(一心)","desc":"필살기 효과를 보유한 아군이 적 처치 시, 한아의 <u>행동 게이지가 <unbreak>#1[i]%</unbreak> 증가</u>한다. 해당 효과는 턴마다 <unbreak>#2[i]</unbreak>회만 발동한다","icon":"SkillIcon_1215_Rank1","params":[0.15,1],"skillAddLevelList":null},{"id":"e2","name":"이관(二觀)","desc":"전투 스킬 발동 후 속도가 <unbreak>#1[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1215_Rank2","params":[0.2,1],"skillAddLevelList":null},{"id":"e3","name":"삼진(三塵)","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1215_BP","params":null,"skillAddLevelList":{"121501":1,"121502":2}},{"id":"e4","name":"사제(四諦)","desc":"필살기 지속 시간이 추가로 <unbreak>#1[i]</unbreak>턴 증가한다","icon":"SkillIcon_1215_Rank4","params":[1],"skillAddLevelList":null},{"id":"e5","name":"오음(五陰)","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1215_Ultra","params":null,"skillAddLevelList":{"121503":2,"121504":2}},{"id":"e6","name":"육정(六正)","desc":"특성의 피해 증가 효과가 추가로 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1215_Rank6","params":[0.1],"skillAddLevelList":null}]',
