    '[{"id":"e1","name":"세양의 기생, 요괴의 숙주","desc":"특성으로 발동한 [양명]의 지속 시간이 <unbreak>#2[i]</unbreak>턴 연장되고, 곽향이 [양명]을 보유할 시 모든 아군의 속도가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1217_Rank1","params":[0.12,1],"skillAddLevelList":null},{"id":"e2","name":"판관의 부적, 영혼의 속박","desc":"곽향이 [양명] 보유 시, 아군은 치명적인 공격을 받아도 <u>전투 불능 상태</u>에 빠지지 않으며, 즉시 자신의 HP 최대치의 <unbreak>#1[i]%</unbreak>만큼 HP를 회복하고 [양명]의 지속 턴 수를 1회 감소시킨다. 해당 효과는 단일 전투에서 <unbreak>#2[i]</unbreak>회 발동할 수 있다","icon":"SkillIcon_1217_Rank2","params":[0.5,2],"skillAddLevelList":null},{"id":"e3","name":"불운의 체질, 반딧불이를 부르는 촛불","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1217_Ultra","params":null,"skillAddLevelList":{"121703":2,"121704":2}},{"id":"e4","name":"떠나지 않는 악귀, 불안정한 갈등","desc":"전투 스킬 또는 특성을 발동해 아군에게 치유 제공 시, 목표의 현재 HP가 낮을수록 치유량이 증가하며, 곽향이 제공하는 치유량이 최대 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1217_Rank4","params":[0.8],"skillAddLevelList":null},{"id":"e5","name":"요괴 사냥, 시왕의 칙령","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1217_BP","params":null,"skillAddLevelList":{"121701":1,"121702":2}},{"id":"e6","name":"동고동락, 언제나 함께","desc":"아군에게 치유 제공 시, 목표가 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1217_Rank6","params":[0.5,2],"skillAddLevelList":null}]',
