    '[{"id":"e1","name":"번뇌를 벗어난 칼날","desc":"[간파•참]과 [간파•멸]이 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가하고, [간파•멸]의 추가 피해 횟수가 <unbreak>#2[i]</unbreak>회 증가한다","icon":"SkillIcon_1221_Rank1","params":[0.2,3],"skillAddLevelList":null},{"id":"e2","name":"새로 태어난 첫 빛","desc":"<u>반격</u>을 발동해 피해를 가할 시 적의 방어력을 <unbreak>#1[i]%</unbreak> 무시한다","icon":"SkillIcon_1221_Rank2","params":[0.2],"skillAddLevelList":null},{"id":"e3","name":"구척검을 휘두르는 기예","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1221_Ultra","params":null,"skillAddLevelList":{"122101":1,"122103":2}},{"id":"e4","name":"망치를 휘두르는 거장","desc":"[간파•참] 또는 [간파•멸] 발동 후 자신의 효과 저항이 <unbreak>#1[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1221_Rank4","params":[0.5,1],"skillAddLevelList":null},{"id":"e5","name":"변치 않는 무기는 돌이 아니니","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1221_BP","params":null,"skillAddLevelList":{"122102":2,"122104":2}},{"id":"e6","name":"담대한 검법, 부드러운 마음","desc":"[막기] 상태일 때, 적이 스킬을 직접 발동할 시 운리를 공격하는지와 상관없이 [간파•멸]을 발동하고 동시에 [막기] 효과를 해제한다. [간파•참] 또는 [간파•멸]을 발동해 피해를 가할 시 치명타 확률이 <unbreak>#1[i]%</unbreak> 증가하고, 물리 속성 <u>저항 관통</u>이 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1221_Rank6","params":[0.15,0.2],"skillAddLevelList":null}]',
