    '{"base":{"hp":110.4,"atk":81.6,"def":48},"growth":{"hp":5.52,"atk":4.08,"def":2.4},"ascensionAdd":[{"hp":0,"atk":0,"def":0},{"hp":44.16,"atk":32.64,"def":19.2},{"hp":88.32,"atk":65.28,"def":38.4},{"hp":132.48,"atk":97.92,"def":57.6},{"hp":176.64,"atk":130.56,"def":76.8},{"hp":220.8,"atk":163.2,"def":96},{"hp":264.96,"atk":195.84,"def":115.2}],"spd":111,"taunt":75}',
    '[{"id":"basic","levelKey":"basic","name":"암기 투척","formula":"moze.basic","icon":"SkillIcon_1223_Normal","params":{"1":[0.5,0.6,0.7,0.8,0.9,1,1.1,1.2,1.3,1.4]},"desc":"지정된 단일 적에게 맥택 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 번개 속성 피해를 가한다","tag":"단일 공격","maxLevel":6,"skillId":"122301"},{"id":"skill","levelKey":"skill","name":"맹속 기습","formula":"moze.skill","icon":"SkillIcon_1223_BP","params":{"1":[0.75,0.825,0.9,0.975,1.05,1.125,1.21875,1.3125,1.40625,1.5,1.575,1.65,1.725,1.8,1.875],"2":[9,9,9,9,9,9,9,9,9,9,9,9,9,9,9]},"desc":"지정된 단일 적을 [사냥감]으로 만들고 해당 목표에게 맥택 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 번개 속성 피해를 가하며, 충전을 <unbreak>#2[i]</unbreak>pt 획득한다.\\n필드 위에 전투 가능한 다른 캐릭터가 없을 시 맥택은 전투 스킬을 사용할 수 없으며, 적의 [사냥감] 상태는 해제된다","tag":"단일 공격","maxLevel":10,"skillId":"122302"},{"id":"ultimate","levelKey":"ultimate","name":"날렵한 예기, 맹렬한 그림자","formula":"moze.ultimate","icon":"SkillIcon_1223_Ultra","params":{"1":[1.62,1.728,1.836,1.944,2.052,2.16,2.295,2.43,2.565,2.7,2.808,2.916,3.024,3.132,3.24]},"desc":"지정된 단일 적에게 맥택 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 번개 속성 피해를 가하고, 해당 목표에게 특성의 <u>추가 공격</u>을 발동한다. 이번 <u>추가 공격</u> 발동 전에 목표가 처치됐을 경우 랜덤 단일 적에게 <u>추가 공격</u>을 발동한다","tag":"단일 공격","maxLevel":10,"skillId":"122303"},{"id":"talent","levelKey":"talent","name":"깃을 꺾어 완성한 칼날","formula":"moze.talent","icon":"SkillIcon_1223_Passive","params":{"1":[0.15,0.165,0.18,0.195,0.21,0.225,0.24375,0.2625,0.28125,0.3,0.315,0.33,0.345,0.36,0.375],"2":[3,3,3,3,3,3,3,3,3,3,3,3,3,3,3],"3":[0.8,0.88,0.96,1.04,1.12,1.2,1.3,1.4,1.5,1.6,1.68,1.76,1.84,1.92,2]},"desc":"필드 위에 [사냥감]이 있을 시 맥택이 <u>퇴장</u> 상태에 진입한다.\\n아군이 [사냥감]을 공격하면 맥택은 추가로 자신의 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 번개 속성 <u>추가 피해</u>를 1회 가하고, 충전을 1pt 소모한다. 충전을 <unbreak>#2[i]</unbreak>pt 소모할 때마다 맥택이 [사냥감]에게 <u>추가 공격</u>을 1회 발동하며, 자신의 공격력의 <color=#f29e38ff><unbreak>#3[i]%</unbreak></color>만큼 번개 속성 피해를 가한다. 충전이 0일 시 목표의 [사냥감] 상태를 해제하고, <u>추가 공격</u> 발동에 필요한 충전 포인트 계산을 초기화한다. 특성의 <u>추가 공격</u>은 충전을 소모하지 않는다","tag":"단일 공격","maxLevel":10,"skillId":"122304"},{"id":"technique","levelKey":"technique","name":"은닉한 날개","formula":"moze.technique","icon":"SkillIcon_1223_Maze","params":{"1":[20],"2":[0.3],"3":[2]},"desc":"비술 사용 후 <unbreak>#1[i]</unbreak>초 동안 지속되는 은신 상태에 진입한다. 은신 상태에선 적에게 들키지 않으며, 맥택이 은신 상태에서 적을 공격해 전투에 진입할 시 피해가 <unbreak>#2[i]%</unbreak> 증가한다, 지속 시간: <unbreak>#3[i]</unbreak>턴","tag":"강화","maxLevel":1,"skillId":"122307"}]',
    '[{"id":"1223101","name":"수묵자객","desc":"특성의 <u>추가 공격</u> 발동 후 전투 스킬 포인트를 <unbreak>#1[i]</unbreak>pt 회복한다. 해당 효과는 <unbreak>#2[i]</unbreak>턴 후 다시 발동할 수 있다","icon":"SkillIcon_1223_SkillTree1","params":{"1":[1],"2":[1]},"unlockAscension":2},{"id":"1223102","name":"비수를 쥔 손","desc":"맥택이 <u>퇴장</u> 상태 해제 시 <u>행동 게이지가 <unbreak>#1[i]%</unbreak> 증가</u>한다. 웨이브가 시작될 때마다 맥택의 <u>행동 게이지가 <unbreak>#2[i]%</unbreak> 증가</u>한다","icon":"SkillIcon_1223_SkillTree2","params":{"1":[0.2],"2":[0.3]},"unlockAscension":4},{"id":"1223103","name":"올곧은 복수심","desc":"필살기를 발동해 피해를 가할 시 <u>추가 공격</u>을 발동한 것으로 간주한다. [사냥감]이 받는 <u>추가 공격</u> 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1223_SkillTree3","params":{"1":[0.25]},"unlockAscension":6}]',
    '[{"id":"1223201","stat":"critDamage","value":0.053,"parentMajor":null,"unlockAscension":0},{"id":"1223202","stat":"atkPct","value":0.04,"parentMajor":"1223101","unlockAscension":2},{"id":"1223203","stat":"critDamage","value":0.053,"parentMajor":"1223101","unlockAscension":3},{"id":"1223204","stat":"hpPct","value":0.04,"parentMajor":null,"unlockAscension":3},{"id":"1223205","stat":"critDamage","value":0.08,"parentMajor":"1223102","unlockAscension":4},{"id":"1223206","stat":"atkPct","value":0.06,"parentMajor":"1223102","unlockAscension":5},{"id":"1223207","stat":"critDamage","value":0.08,"parentMajor":null,"unlockAscension":5},{"id":"1223208","stat":"hpPct","value":0.06,"parentMajor":"1223103","unlockAscension":6},{"id":"1223209","stat":"atkPct","value":0.08,"parentMajor":"1223103","unlockAscension":6},{"id":"1223210","stat":"critDamage","value":0.107,"parentMajor":"1223103","unlockAscension":6}]',
    '[{"id":"e1","name":"다짐","desc":"전투 진입 후 맥택은 에너지를 <unbreak>#2[i]</unbreak>pt 회복한다. 특성의 <u>추가 피해</u>를 1회 발동할 때마다 맥택은 에너지를 <unbreak>#1[i]</unbreak>pt 회복한다","icon":"SkillIcon_1223_Rank1","params":[2,20],"skillAddLevelList":null},{"id":"e2","name":"정벌","desc":"모든 아군이 [사냥감]이 된 적에게 피해를 가할 시 치명타 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1223_Rank2","params":[0.4],"skillAddLevelList":null},{"id":"e3","name":"추격","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1223_Ultra","params":null,"skillAddLevelList":{"122303":2,"122304":2}},{"id":"e4","name":"은폐","desc":"필살기 발동 시 맥택이 가하는 피해가 <unbreak>#1[f1]%</unbreak> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1223_Rank4","params":[0.3,2],"skillAddLevelList":null},{"id":"e5","name":"기만","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1223_BP","params":null,"skillAddLevelList":{"122301":1,"122302":2}},{"id":"e6","name":"단심","desc":"특성의 <u>추가 공격</u> 피해 배율이 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1223_Rank6","params":[0.25],"skillAddLevelList":null}]',
