    '[{"id":"1301101","name":"새로운 레시피","desc":"자신이 제공하는 치유량이 격파 특수효과의 <unbreak>#1[i]%</unbreak>만큼 증가한다. 제공하는 치유량은 최대 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1301_SkillTree1","params":{"1":[0.5],"2":[0.75]},"unlockAscension":2},{"id":"1301102","name":"천연 효모","desc":"필살기 발동 후 즉시 자신의 <u>행동 게이지가 <unbreak>100%</unbreak> 증가</u>한다","icon":"SkillIcon_1301_SkillTree2","params":null,"unlockAscension":4},{"id":"1301103","name":"위하여!","desc":"갤러거가 [솟구치는 거품]을 발동하여 [만취] 상태에 빠진 목표를 공격하면 이번에 특성이 제공하는 HP 회복 효과가 아군 동료에게도 적용된다","icon":"SkillIcon_1301_SkillTree3","params":null,"unlockAscension":6}]',
