    '[{"id":"e1","name":"솔티 도그","desc":"갤러거가 전투 진입 후 에너지를 <unbreak>#1[i]</unbreak>pt 회복하고, 효과 저항이 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1301_Rank1","params":[20,0.5],"skillAddLevelList":null},{"id":"e2","name":"라이온스 테일","desc":"전투 스킬 발동 시 지정된 단일 아군의 <u>디버프 효과</u>를 <unbreak>#1[i]</unbreak>개 해제하고, 해당 아군의 효과 저항을 <unbreak>#2[i]%</unbreak> 증가시킨다. 지속 시간: <unbreak>#3[i]</unbreak>턴","icon":"SkillIcon_1301_Rank2","params":[1,0.3,2],"skillAddLevelList":null},{"id":"e3","name":"코프스 리바이버","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1301_BP","params":null,"skillAddLevelList":{"130101":1,"130102":2,"130108":1}},{"id":"e4","name":"라스트 워드","desc":"갤러거가 필살기로 가하는 [만취] 상태의 지속 시간이 <unbreak>#1[i]</unbreak>턴 증가한다","icon":"SkillIcon_1301_Rank4","params":[1],"skillAddLevelList":null},{"id":"e5","name":"데스 인 디 애프터눈","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1301_Ultra","params":null,"skillAddLevelList":{"130103":2,"130104":2}},{"id":"e6","name":"블러드 앤 샌드","desc":"갤러거의 격파 특수효과가 <unbreak>#1[i]%</unbreak> 증가하고, 약점 격파 효율이 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1301_Rank6","params":[0.2,0.2],"skillAddLevelList":null}]',
