    '[{"id":"1302101","name":"경건","desc":"턴 시작 시 즉시 [승격]을 <unbreak>#1[i]</unbreak>스택 획득한다","icon":"SkillIcon_1302_SkillTree1","params":{"1":[1]},"unlockAscension":2},{"id":"1302102","name":"너그러움","desc":"적이 전투 진입 시 자신의 에너지를 즉시 <unbreak>#1[i]</unbreak>pt 회복한다","icon":"SkillIcon_1302_SkillTree2","params":{"1":[2]},"unlockAscension":4},{"id":"1302103","name":"용기","desc":"현재 HP 백분율이 <unbreak>#1[i]%</unbreak> 이하인 적에게 주는 피해가 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1302_SkillTree3","params":{"1":[0.5],"2":[0.15]},"unlockAscension":6}]',
