    '[{"id":"e1","name":"심미왕국의 결함","desc":"[승격] 스택마다 추가로 치명타 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1302_Rank1","params":[0.04],"skillAddLevelList":null},{"id":"e2","name":"아게이트의 겸손","desc":"필살기 발동 시 적이 <unbreak>#1[i]</unbreak>기 이상일 경우 공격력이 <unbreak>#2[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#3[i]</unbreak>턴","icon":"SkillIcon_1302_Rank2","params":[3,0.4,1],"skillAddLevelList":null},{"id":"e3","name":"가시밭길의 영광","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1302_BP","params":null,"skillAddLevelList":{"130202":2,"130204":2}},{"id":"e4","name":"나팔의 헌신","desc":"전투 시작 시 [승격]을 <unbreak>#1[i]</unbreak>스택 획득하고, 특성의 효과 최대 중첩수가 <unbreak>#2[i]</unbreak>스택 증가한다","icon":"SkillIcon_1302_Rank4","params":[2,2],"skillAddLevelList":null},{"id":"e5","name":"우주 어딘가의 눈","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1302_Ultra","params":null,"skillAddLevelList":{"130201":1,"130203":2,"130214":2}},{"id":"e6","name":"「그분」의 빛","desc":"필살기 발동 시 적의 방어력을 <unbreak>#1[i]%</unbreak> 무시한다","icon":"SkillIcon_1302_Rank6","params":[0.3],"skillAddLevelList":null}]',
