    '[{"id":"e1","name":"죄수의 딜레마","desc":"[견고한 칩]을 보유한 아군의 치명타 피해가 <unbreak>#1[i]%</unbreak> 증가한다. 필살기 발동 후 모든 아군에게 실드 [견고한 칩]을 제공한다. 실드량은 전투 스킬이 제공하는 실드량의 <unbreak>#2[i]%</unbreak>다. 지속 시간: <unbreak>#3[i]</unbreak>턴","icon":"SkillIcon_1304_Rank1","params":[0.2,1,3],"skillAddLevelList":null},{"id":"e2","name":"제한된 합리성","desc":"일반 공격 발동 시 목표의 모든 속성 저항이 <unbreak>#2[i]%</unbreak> 감소한다. 지속 시간: <unbreak>#3[i]</unbreak>턴","icon":"SkillIcon_1304_Rank2","params":[1.2,0.12,3],"skillAddLevelList":null},{"id":"e3","name":"최고 배당","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1304_Ultra","params":null,"skillAddLevelList":{"130401":1,"130403":2}},{"id":"e4","name":"사형수의 역설","desc":"특성의 <u>추가 공격</u> 발동 시, 우선 어벤츄린의 방어력이 <unbreak>#1[i]%</unbreak> 증가한다, 지속 시간: <unbreak>#2[i]</unbreak>턴. 또한, 특성 <u>추가 공격</u>의 공격 단수가 추가로 <unbreak>#3[i]</unbreak>단 증가한다","icon":"SkillIcon_1304_Rank4","params":[0.4,2,3],"skillAddLevelList":null},{"id":"e5","name":"모호성 회피","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1304_BP","params":null,"skillAddLevelList":{"130402":2,"130404":2}},{"id":"e6","name":"사슴 사냥 게임","desc":"실드를 보유한 동료 1명마다 어벤츄린이 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가하며, 최대 <unbreak>#2[i]%</unbreak>를 초과하지 않는다","icon":"SkillIcon_1304_Rank6","params":[0.5,1.5],"skillAddLevelList":null}]',
