    '[{"id":"e1","name":"교만은 재앙을 낳는다","desc":"행적 [귀납]의 중첩 스택 수 상한이 <unbreak>#1[i]</unbreak>스택 증가한다. 전투 시작 시 [귀납] <unbreak>#2[i]</unbreak>스택을 즉시 획득한다. 먼저 행적 [귀납]을 개방해야 한다","icon":"SkillIcon_1305_Rank1","params":[4,4],"skillAddLevelList":null},{"id":"e2","name":"작은 것에 숨겨진 진리","desc":"특성의 <u>추가 공격</u>이 목표를 명중할 시, 목표가 <u>디버프 효과</u>를 1개 보유할 때마다 추가로 Dr. 레이시오 공격력의 <unbreak>#1[i]%</unbreak>만큼 허수 속성 <u>추가 피해</u>를 가한다. 해당 효과는 <u>추가 공격</u>을 할 때마다 최대 <unbreak>#2[i]</unbreak>회 발동된다","icon":"SkillIcon_1305_Rank2","params":[0.2,4],"skillAddLevelList":null},{"id":"e3","name":"너 자신을 알라","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1305_Ultra","params":null,"skillAddLevelList":{"130501":1,"130503":2}},{"id":"e4","name":"맹목은 미련을 낳는다","desc":"특성 발동 시 Dr. 레이시오가 추가로 에너지를 <unbreak>#1[i]</unbreak>pt 회복한다","icon":"SkillIcon_1305_Rank4","params":[15],"skillAddLevelList":null},{"id":"e5","name":"노 없는 배는 바다를 건널 수 없다","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1305_BP","params":null,"skillAddLevelList":{"130502":2,"130504":2}},{"id":"e6","name":"영원한 것은 진리뿐","desc":"[현자의 짧은 생각]의 발동 효과가 추가로 <unbreak>#1[i]</unbreak>회 증가하고, 특성의 <u>추가 공격</u>으로 가하는 피해가 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1305_Rank6","params":[1,0.5],"skillAddLevelList":null}]',
    '[]'
);

