    '[{"id":"e1","name":"적막의 하늘, 진언의 시작","desc":"<u>디버프 효과</u>를 보유한 적에게 피해를 가할 시 치명타 확률이 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1308_Rank1","params":[0.18],"skillAddLevelList":null},{"id":"e2","name":"고요한 뇌명, 잠잠해진 폭풍","desc":"행적 [나락] 최대치 도달에 필요한 「공허」 운명의 길 캐릭터의 수가 1명 감소한다. 자신의 턴이 시작되면 [꿈 조각]을 1pt 획득하고, 동시에 [아즈사카]가 가장 많은 적에게 [아즈사카]를 1스택 부여한다","icon":"SkillIcon_1308_Rank2","params":null,"skillAddLevelList":null},{"id":"e3","name":"영면을 깨운 추위","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1308_Ultra","params":null,"skillAddLevelList":{"130801":1,"130803":2,"130814":2,"130815":2,"130816":2,"130817":2}},{"id":"e4","name":"거울 속 존재를 비추는 불길","desc":"적이 전투 진입 시 해당 적을 필살기 피해 취약 상태에 빠트려 받는 필살기 피해를 <unbreak>#1[i]%</unbreak> 증가시킨다","icon":"SkillIcon_1308_Rank4","params":[0.08],"skillAddLevelList":null},{"id":"e5","name":"부서진 땅, 떠도는 영혼","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1308_BP","params":null,"skillAddLevelList":{"130802":2,"130804":2}},{"id":"e6","name":"속박을 푼 재앙","desc":"아케론이 가하는 필살기 피해의 모든 속성 <u>저항 관통</u>이 <unbreak>#1[i]%</unbreak> 증가한다. 일반 공격과 전투 스킬을 발동하여 가하는 피해는 동시에 필살기 피해로 간주되며, 약점 속성을 무시하고 적의 강인성을 소모한다. 약점 격파 시 번개 속성의 약점 격파 효과를 발동한다","icon":"SkillIcon_1308_Rank6","params":[0.2],"skillAddLevelList":null}]',
