    '[{"id":"e1","name":"미소의 국가","desc":"[협주] 상태일 시 모든 아군의 모든 속성 <u>저항 관통</u>이 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1309_Rank1","params":[0.24],"skillAddLevelList":null},{"id":"e2","name":"두 사람의 애프터눈 티","desc":"[협주] 상태일 시 모든 아군의 속도가 <unbreak>#1[i]%</unbreak> 증가한다. 특성의 에너지 회복 효과가 추가로 <unbreak>#2[i]</unbreak>pt 증가한다","icon":"SkillIcon_1309_Rank2","params":[0.16,1],"skillAddLevelList":null},{"id":"e3","name":"뒤집힌 현의 궁전","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1309_BP","params":null,"skillAddLevelList":{"130902":2,"130903":2}},{"id":"e4","name":"빗방울의 열쇠","desc":"필살기 발동 시 모든 아군의 <u>제어류 디버프 상태</u>를 해제하고, 모든 아군은 로빈이 [협주] 상태일 동안 효과 저항이 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1309_Rank4","params":[0.5],"skillAddLevelList":null},{"id":"e5","name":"고독한 별의 눈물","desc":"일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1309_Normal","params":null,"skillAddLevelList":{"130901":1,"130904":2}},{"id":"e6","name":"달이 숨은 자정","desc":"[협주] 상태일 시 필살기로 가하는 물리 속성 <u>추가 피해</u>의 치명타 피해가 추가로 <unbreak>#2[i]%</unbreak> 증가한다. [달이 숨은 자정] 효과는 최대 <unbreak>#1[i]</unbreak>회 발동되며, 필살기를 발동할 때마다 발동 횟수가 초기화된다","icon":"SkillIcon_1309_Rank6","params":[8,4.5],"skillAddLevelList":null}]',
