    '[{"id":"e1","name":"흔들리는 환영","desc":"필살기 발동 시 필드 위 적 1명당 해당 필살기 공격 단수가 추가로 <unbreak>#1[i]</unbreak>단 증가하며, 최대 추가로 <unbreak>#2[i]</unbreak>단까지 증가한다","icon":"SkillIcon_1312_Rank1","params":[1,5],"skillAddLevelList":null},{"id":"e2","name":"청춘의 창연한 눈빛","desc":"필살기의 단수별 공격 전 <unbreak>#3[i]%</unbreak>의 <u>기본 확률</u>로 목표의 방어력을 <unbreak>#1[i]%</unbreak> 감소시킨다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1312_Rank2","params":[0.16,3,0.24],"skillAddLevelList":null},{"id":"e3","name":"행복한 세월의 그림자","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1312_Ultra","params":null,"skillAddLevelList":{"131201":1,"131203":2}},{"id":"e4","name":"다정한 모습","desc":"필살기의 단수별 공격 피해 배율이 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1312_Rank4","params":[0.06],"skillAddLevelList":null},{"id":"e5","name":"최초의 사랑과 우정","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1312_BP","params":null,"skillAddLevelList":{"131202":2,"131204":2}},{"id":"e6","name":"오랫동안 잊고 있던 동경","desc":"필살기 발동 시, 자신이 가하는 피해가 자신의 턴이 종료될 때까지 <unbreak>#2[i]%</unbreak> 증가하며, 다음 전투 스킬 발동 후 아군이 전투 스킬 포인트를 <unbreak>#1[i]</unbreak>pt 회복한다","icon":"SkillIcon_1312_Rank6","params":[1,0.3],"skillAddLevelList":null}]',
