formula":"sunday.talent","icon":"SkillIcon_1313_Passive","params":{"1":[0.1,0.11,0.12,0.13,0.14,0.15,0.1625,0.175,0.1875,0.2,0.21,0.22,0.23,0.24,0.25],"2":[3,3,3,3,3,3,3,3,3,3,3,3,3,3,3]},"desc":"전투 스킬 발동 시 목표의 치명타 확률이 <color=#f29e38ff><unbreak>#1[f1]%</unbreak></color> 증가한다, 지속 시간: <unbreak>#2[i]</unbreak>턴","tag":"서포트","maxLevel":10,"skillId":"131304"},{"id":"technique","levelKey":"technique","name":"영광의 신비","formula":"sunday.technique","icon":"SkillIcon_1313_Maze","params":{"1":[0.5],"2":[2]},"desc":"비술 사용 후 다음 전투에서 선데이가 처음으로 아군에게 스킬을 발동하면 목표가 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가한다, 지속 시간: <unbreak>#2[i]</unbreak>턴","tag":"서포트","maxLevel":1,"skillId":"131307"}]',
    '[{"id":"1313101","name":"주일을 향한 갈망","desc":"필살기 발동 시 목표에게 회복한 에너지가 <unbreak>#1[i]</unbreak>pt 미만일 시, 회복하는 에너지가 <unbreak>#1[i]</unbreak>pt까지 증가한다","icon":"SkillIcon_1313_SkillTree1","params":{"1":[40]},"unlockAscension":2},{"id":"1313102","name":"먼지를 털어내는 숭고함","desc":"전투 시작 시 선데이의 에너지를 <unbreak>#1[i]</unbreak>pt 회복한다","icon":"SkillIcon_1313_SkillTree2","params":{"1":[25]},"unlockAscension":4},{"id":"1313103","name":"손바닥 위 안식처","desc":"전투 스킬 발동 시 목표의 <u>디버프 효과</u>를 <unbreak>#1[i]</unbreak>개 해제한다","icon":"SkillIcon_1313_SkillTree3","params":{"1":[1]},"unlockAscension":6}]',
