    '[{"id":"e1","name":"천년의 고요한 끝","desc":"선데이가 전투 스킬 발동 시 목표 캐릭터가 피해를 가하면 목표의 방어력을 <unbreak>#2[i]%</unbreak> 무시하고, 소환물이 피해를 가하면 목표의 방어력을 <unbreak>#3[i]%</unbreak> 무시한다, 지속 시간: <unbreak>#1[i]</unbreak>턴","icon":"SkillIcon_1313_Rank1","params":[2,0.16,0.4],"skillAddLevelList":null},{"id":"e2","name":"부족함을 메우는 믿음","desc":"처음 필살기 발동 후 전투 스킬 포인트를 <unbreak>#2[i]</unbreak>pt 회복한다. [은혜 입은 자]가 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1313_Rank2","params":[0.3,2],"skillAddLevelList":null},{"id":"e3","name":"가시의 은둔처","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1313_Ultra","params":null,"skillAddLevelList":{"131301":1,"131303":2}},{"id":"e4","name":"조각의 머리말","desc":"턴 시작 시 에너지를 <unbreak>#1[i]</unbreak>pt 회복한다","icon":"SkillIcon_1313_Rank4","params":[8],"skillAddLevelList":null},{"id":"e5","name":"은하를 표류하는 종이배","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1313_BP","params":null,"skillAddLevelList":{"131302":2,"131304":2}},{"id":"e6","name":"뭇별의 떠들썩한 첫걸음","desc":"특성의 치명타 확률 증가 효과가 최대 <unbreak>#1[i]</unbreak>스택 중첩되며, 특성의 지속 시간이 <unbreak>#3[i]</unbreak>턴 증가한다. 선데이가 필살기 발동 시 목표에게 특성의 치명타 확률 증가 효과를 부여할 수 있다. 특성의 치명타 확률 증가 효과 발동 시 목표의 치명타 확률이 <unbreak>100%</unbreak>를 초과하면, 1%를 초과할 때마다 치명타 피해가 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1313_Rank6","params":[3,0.02,1],"skillAddLevelList":null}]',
    '[]'
);

INSERT INTO characters (id, slug, name, element, path, rarity, is_beta, released_at, stats, actions, major_traces, minor_traces, eidolons, tags) VALUES (
