    '[{"id":"basic","levelKey":"basic","name":"두개골을 부수는 발굽","formula":"boothill.basic","icon":"SkillIcon_1315_Normal","params":{"1":[0.5,0.6,0.7,0.8,0.9,1,1.1,1.2,1.3,1.4]},"desc":"지정된 단일 적에게 부트힐 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 물리 속성 피해를 가한다","tag":"단일 공격","maxLevel":6,"skillId":"131501"},{"id":"basic2","levelKey":"basic","name":"리볼버 패닝","formula":"boothill.basic2","icon":"SkillIcon_1315_Normal02","params":{"1":[1.1,1.32,1.54,1.76,1.98,2.2,2.42,2.64,2.86,3.08]},"desc":"지정된 단일 적에게 부트힐 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 물리 속성 피해를 가한다.\\n강화된 일반 공격은 전투 스킬 포인트를 회복할 수 없으며, [목숨 건 대치] 상태의 적만을 목표로 삼을 수 있다","tag":"단일 공격","maxLevel":6,"skillId":"131508"},{"id":"skill","levelKey":"skill","name":"뜨거운 자갈 위 탱고","formula":"boothill.skill","icon":"SkillIcon_1315_BP","params":{"1":[0.15,0.165,0.18,0.195,0.21,0.225,0.24375,0.2625,0.28125,0.3,0.315,0.33,0.345,0.36,0.375],"2":[0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15,0.15],"3":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2]},"desc":"지정된 단일 적과 자신이 [목숨 건 대치] 상태에 진입한다. 부트힐의 일반 공격이 강화되고 전투 스킬을 발동할 수 없다, 지속 시간: <unbreak>#3[i]</unbreak>턴. 부트힐의 턴이 시작될 때마다 지속 턴 수가 1 감소한다.\\n[목숨 건 대치] 상태의 적은 도발 상태에 빠진다. 해당 목표/부트힐이 상대의 공격을 받을 시 받는 피해가 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>/<unbreak>#2[i]%</unbreak> 증가한다.\\n해당 목표가 처치되거나 약점이 격파된 후, 부트힐은 [포켓 어드벤티지]를 1스택 획득하고, [목숨 건 대치]가 해제된다.\\n해당 전투 스킬은 에너지를 회복할 수 없다. 해당 전투 스킬 발동 후, 이번 턴은 종료되지 않는다","tag":"방해","maxLevel":10,"skillId":"131502"},{"id":"ultimate","levelKey":"ultimate","name":"더스트 데빌의 선셋 로데오","formula":"boothill.ultimate","icon":"SkillIcon_1315_Ultra","params":{"1":[2.4,2.56,2.72,2.88,3.04,3.2,3.4,3.6,3.8,4,4.16,4.32,4.48,4.64,4.8],"2":[0.3,0.31,0.32,0.33,0.34,0.35,0.3625,0.375,0.3875,0.4,0.41,0.42,0.43,0.44,0.45],"3":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2]},"desc":"지정된 단일 적에게 물리 약점을 부여한다, 지속 시간: <unbreak>#3[i]</unbreak>턴\\n해당 목표에게 부트힐 공격력의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 물리 속성 피해를 가하고, <u>행동 게이지를 <color=#f29e38ff><unbreak>#2[i]%</unbreak></color> 감소</u>시킨다","tag":"단일 공격","maxLevel":10,"skillId":"131503"},{"id":"talent","levelKey":"talent","name":"실린더 속 다섯 발","formula":"boothill.talent","icon":"SkillIcon_1315_Passive","params":{"1":[0.35,0.385,0.42,0.455,0.49,0.525,0.56875,0.6125,0.65625,0.7,0.735,0.77,0.805,0.84,0.875],"2":[0.6,0.66,0.72,0.78,0.84,0.9,0.975,1.05,1.125,1.2,1.26,1.32,1.38,1.44,1.5],"3":[0.85,0.935,1.02,1.105,1.19,1.275,1.38125,1.4875,1.59375,1.7,1.785,1.87,1.955,2.04,2.125],"4":[0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5],"5":[3,3,3,3,3,3,3,3,3,3,3,3,3,3,3],"6":[16,16,16,16,16,16,16,16,16,16,16,16,16,16,16]},"desc":"[포켓 어드벤티지] 1스택마다 강화된 일반 공격의 강인성 감소 수치가 <unbreak>#4[i]%</unbreak> 증가한다. 최대 중첩수: <unbreak>#5[i]</unbreak>스택\\n강화된 일반 공격 발동 중에 목표가 <u>약점 격파 상태</u>일 경우, [포켓 어드벤티지] 스택 수에 따라 목표에게 부트힐 물리 속성 격파 피해의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>/<color=#f29e38ff><unbreak>#2[i]%</unbreak></color>/<color=#f29e38ff><unbreak>#3[i]%</unbreak></color>만큼 <u>격파 피해</u>를 가한다. 해당 피해에 계산되는 강인성 최대치는 일반 공격 [두개골을 부수는 발굽]의 기초 강인성 감소 수치의 <unbreak>#6[i]</unbreak>배를 넘을 수 없다.\\n전투 승리 후, 부트힐은 [포켓 어드벤티지]를 다음 전투까지 보류할 수 있다","tag":"강화","maxLevel":10,"skillId":"131504"},{"id":"technique","levelKey":"technique","name":"3-9x의 미소","formula":"boothill.technique","icon":"SkillIcon_1315_Maze","params":{"1":[2]},"desc":"비술 사용 후 다음번 전투에서 처음 전투 스킬을 발동할 시, 목표에게 필살기와 동일한 물리 약점을 부여한다. 지속 시간: <unbreak>#1[i]</unbreak>턴","tag":"강화","maxLevel":1,"skillId":"131507"}]',
    '[{"id":"1315101","name":"고스트 로딩","desc":"자신의 치명타 확률/치명타 피해가 증가한다. 증가 수치는 격파 특수효과의 <unbreak>#1[i]%</unbreak>/<unbreak>#3[i]%</unbreak>이며, 치명타 확률/치명타 피해는 최대 <unbreak>#2[i]%</unbreak>/<unbreak>#4[i]%</unbreak> 증가한다","icon":"SkillIcon_1315_SkillTree1","params":{"1":[0.1],"2":[0.3],"3":[0.5],"4":[1.5]},"unlockAscension":2},{"id":"1315102","name":"어보브 스네이크","desc":"부트힐이 [목숨 건 대치] 상태일 시 [목숨 건 대치] 상태가 아닌 목표에게 받는 피해가 <unbreak>#1[i]%</unbreak> 감소한다","icon":"SkillIcon_1315_SkillTree2","params":{"1":[0.3]},"unlockAscension":4},{"id":"1315103","name":"포인트 블랭크","desc":"[목숨 건 대치] 상태에서 [포켓 어드벤티지] 획득 시, 에너지를 <unbreak>#1[i]</unbreak>pt 회복한다. 해당 효과는 [포켓 어드벤티지]를 초과해 획득할 때도 발동된다","icon":"SkillIcon_1315_SkillTree3","params":{"1":[10]},"unlockAscension":6}]',
    '[{"id":"1315201","stat":"breakEffect","value":0.053,"parentMajor":null,"unlockAscension":0},{"id":"1315202","stat":"atkPct","value":0.04,"parentMajor":"1315101","unlockAscension":2},{"id":"1315203","stat":"breakEffect","value":0.053,"parentMajor":"1315101","unlockAscension":3},{"id":"1315204","stat":"hpPct","value":0.04,"parentMajor":null,"unlockAscension":3},{"id":"1315205","stat":"breakEffect","value":0.08,"parentMajor":"1315102","unlockAscension":4},{"id":"1315206","stat":"atkPct","value":0.06,"parentMajor":"1315102","unlockAscension":5},{"id":"1315207","stat":"breakEffect","value":0.08,"parentMajor":null,"unlockAscension":5},{"id":"1315208","stat":"hpPct","value":0.06,"parentMajor":"1315103","unlockAscension":6},{"id":"1315209","stat":"atkPct","value":0.08,"parentMajor":"1315103","unlockAscension":6},{"id":"1315210","stat":"breakEffect","value":0.107,"parentMajor":"1315103","unlockAscension":6}]',
    '[{"id":"e1","name":"황야의 론스타","desc":"전투 시작 시 [포켓 어드벤티지]를 1스택 획득한다. 부트힐이 피해를 가할 시 적의 방어력을 <unbreak>#1[i]%</unbreak> 무시한다","icon":"SkillIcon_1315_Rank1","params":[0.16],"skillAddLevelList":null},{"id":"e2","name":"마일스톤 딜러","desc":"[목숨 건 대치] 상태에서 [포켓 어드벤티지] 획득 시, 전투 스킬 포인트를 <unbreak>#1[i]</unbreak>개 회복하고 격파 특수효과가 <unbreak>#2[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#3[i]</unbreak>턴. 해당 효과는 1턴 내에 중복 발동할 수 없으며, [포켓 어드벤티지]를 초과해 획득할 때도 발동된다","icon":"SkillIcon_1315_Rank2","params":[1,0.3,2],"skillAddLevelList":null},{"id":"e3","name":"대리석 과수원의 파수꾼","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1315_Ultra","params":null,"skillAddLevelList":{"131501":1,"131503":2,"131508":1}},{"id":"e4","name":"냉육 주방장","desc":"[목숨 건 대치] 상태의 적이 부트힐에게 피격 시 받는 피해가 추가로 <unbreak>#1[i]%</unbreak> 증가한다. 부트힐이 [목숨 건 대치] 상태의 적에게 피격 시 받는 피해 증가 효과가 <unbreak>#2[i]%</unbreak> 감소한다","icon":"SkillIcon_1315_Rank4","params":[0.12,0.12],"skillAddLevelList":null},{"id":"e5","name":"그루터기 연설가","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1315_BP","params":null,"skillAddLevelList":{"131502":2,"131504":2}},{"id":"e6","name":"쇠창살 여관의 라쿤","desc":"특성을 발동하여 <u>격파 피해</u>를 가할 시, 목표에게 추가로 기존 피해 배율의 <unbreak>#1[i]%</unbreak>만큼 <u>격파 피해</u>를 가하고, 인접한 목표에게 추가로 기존 피해 배율의 <unbreak>#2[i]%</unbreak>만큼 <u>격파 피해</u>를 가한다","icon":"SkillIcon_1315_Rank6","params":[0.4,0.7],"skillAddLevelList":null}]',
