    '[{"id":"basic","levelKey":"basic","name":"<unbreak>100</unbreak>층짜리 미니 로켓","formula":"tribbie.basic","icon":"SkillIcon_1403_Normal","params":{"1":[0.15,0.18,0.21,0.24,0.27,0.3,0.33,0.36,0.39,0.42],"2":[0.075,0.09,0.105,0.12,0.135,0.15,0.165,0.18,0.195,0.21]},"desc":"지정된 단일 적에게 트리비 HP 최대치의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 양자 속성 피해를 가하고, 인접한 목표에게 트리비 HP 최대치의 <color=#f29e38ff><unbreak>#2[i]%</unbreak></color>만큼 양자 속성 피해를 가한다","tag":"확산","maxLevel":6,"skillId":"140301"},{"id":"skill","levelKey":"skill","name":"선물이 다 어디 갔지?","formula":"tribbie.skill","icon":"SkillIcon_1403_BP","params":{"1":[0.12,0.132,0.144,0.156,0.168,0.18,0.195,0.21,0.225,0.24,0.252,0.264,0.276,0.288,0.3],"2":[3,3,3,3,3,3,3,3,3,3,3,3,3,3,3]},"desc":"<unbreak>#2[i]</unbreak>턴 동안 지속되는 [신의 계시]를 획득하며, 자신의 턴이 시작될 때마다 지속 턴 수가 1 감소한다. 트리비가 [신의 계시]를 보유할 시 모든 아군의 모든 속성 <u>저항 관통</u>이 <color=#f29e38ff><unbreak>#1[f1]%</unbreak></color> 증가한다","tag":"서포트","maxLevel":10,"skillId":"140302"},{"id":"ultimate","levelKey":"ultimate","name":"여기에 누가 살고 있게?","formula":"tribbie.ultimate","icon":"SkillIcon_1403_Ultra","params":{"1":[0.15,0.165,0.18,0.195,0.21,0.225,0.24375,0.2625,0.28125,0.3,0.315,0.33,0.345,0.36,0.375],"2":[0.15,0.165,0.18,0.195,0.21,0.225,0.24375,0.2625,0.28125,0.3,0.315,0.33,0.345,0.36,0.375],"3":[0.06,0.066,0.072,0.078,0.084,0.09,0.0975,0.105,0.1125,0.12,0.126,0.132,0.138,0.144,0.15],"4":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2]},"desc":"결계를 활성화하고, 모든 적에게 트리비 HP 최대치의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 양자 속성 피해를 가한다.\\n결계 지속 시간 동안 적이 받는 피해가 <color=#f29e38ff><unbreak>#2[f1]%</unbreak></color> 증가한다. 아군에게 피격 후, 피격된 목표가 1기 있을 때마다 피격된 목표 중 현재 HP가 가장 높은 목표에게 트리비 HP 최대치의 <color=#f29e38ff><unbreak>#3[f1]%</unbreak></color>만큼 양자 속성 <u>추가 피해</u>를 1회 가한다.\\n결계는 <unbreak>#4[i]</unbreak>턴 동안 지속되며, 자신의 턴이 시작될 때마다 결계 지속 턴 수가 1 감소한다","tag":"범위 공격","maxLevel":10,"skillId":"140303"},{"id":"talent","levelKey":"talent","name":"트리비는 너무 바빠","formula":"tribbie.talent","icon":"SkillIcon_1403_Passive","params":{"1":[0.09,0.099,0.108,0.117,0.126,0.135,0.14625,0.1575,0.16875,0.18,0.189,0.198,0.207,0.216,0.225]},"desc":"다른 아군 캐릭터가 필살기를 발동하면 트리비가 <u>추가 공격</u>을 발동하여 모든 적에게 트리비 HP 최대치의 <color=#f29e38ff><unbreak>#1[f1]%</unbreak></color>만큼 양자 속성 피해를 가한다. 해당 효과는 캐릭터마다 최대 1회 발동하며, 트리비가 필살기를 발동할 시 다른 아군 캐릭터의 발동 가능 횟수가 초기화된다. <u>추가 공격</u> 발동 전에 목표가 처치되면 필드에 새로 등장한 적에게 <u>추가 공격</u>을 발동한다","tag":"범위 공격","maxLevel":10,"skillId":"140304"},{"id":"technique","levelKey":"technique","name":"모두 다 같이 손뼉을","formula":"tribbie.technique","icon":"SkillIcon_1403_Maze","params":{"1":[3]},"desc":"비술 사용 후 전투 진입 시 [신의 계시]를 획득한다, 지속 시간: <unbreak>#1[i]</unbreak>턴","tag":"강화","maxLevel":1,"skillId":"140307"}]',
    '[{"id":"1403101","name":"성벽 밖의 어린양…","desc":"특성의 <u>추가 공격</u> 발동 후, 트리비가 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가한다, 해당 효과 최대 중첩수: <unbreak>#2[i]</unbreak>스택, 지속 시간: <unbreak>#3[i]</unbreak>턴","icon":"SkillIcon_1403_SkillTree1","params":{"1":[0.72],"2":[3],"3":[3]},"unlockAscension":2},{"id":"1403102","name":"날개 달린 유리구슬!","desc":"결계 지속 시간 동안 트리비의 HP 최대치가 모든 아군 캐릭터 HP 최대치 총합의 <unbreak>#1[i]%</unbreak>만큼 증가한다","icon":"SkillIcon_1403_SkillTree2","params":{"1":[0.09]},"unlockAscension":4},{"id":"1403103","name":"갈림길 옆 돌멩이?","desc":"전투 시작 시 트리비의 에너지가 <unbreak>#1[i]</unbreak>pt 회복된다. 다른 아군이 공격 후 목표를 1기 명중할 때마다 트리비의 에너지가 <unbreak>#2[f1]</unbreak>pt 회복된다","icon":"SkillIcon_1403_SkillTree3","params":{"1":[30],"2":[1.5]},"unlockAscension":6}]',
    '[{"id":"1403201","stat":"critDamage","value":0.053,"parentMajor":null,"unlockAscension":0},{"id":"1403202","stat":"critRate","value":0.026999999,"parentMajor":"1403101","unlockAscension":2},{"id":"1403203","stat":"critDamage","value":0.053,"parentMajor":"1403101","unlockAscension":3},{"id":"1403204","stat":"hpPct","value":0.04,"parentMajor":null,"unlockAscension":3},{"id":"1403205","stat":"critDamage","value":0.08,"parentMajor":"1403102","unlockAscension":4},{"id":"1403206","stat":"critRate","value":0.04,"parentMajor":"1403102","unlockAscension":5},{"id":"1403207","stat":"critDamage","value":0.08,"parentMajor":null,"unlockAscension":5},{"id":"1403208","stat":"hpPct","value":0.06,"parentMajor":"1403103","unlockAscension":6},{"id":"1403209","stat":"critRate","value":0.053,"parentMajor":"1403103","unlockAscension":6},{"id":"1403210","stat":"critDamage","value":0.107,"parentMajor":"1403103","unlockAscension":6}]',
    '[{"id":"e1","name":"설탕을 줍는 축제","desc":"결계 지속 시간 동안 아군이 적을 공격하면 결계가 <u>추가 피해</u>를 가하는 목표에게 추가로 이번 공격 총 피해량의 <unbreak>#1[i]%</unbreak>만큼 <u>확정 피해</u>를 가한다","icon":"SkillIcon_1403_Rank1","params":[0.24],"skillAddLevelList":null},{"id":"e2","name":"좋은 꿈을 탐방하는 길잡이","desc":"결계가 가하는 <u>추가 피해</u>가 기존 피해의 <unbreak>#1[i]%</unbreak>로 증가한다. 결계가 <u>추가 피해</u>를 가할 시 추가 피해를 <unbreak>#2[i]</unbreak>회 추가로 가한다","icon":"SkillIcon_1403_Rank2","params":[1.2,1],"skillAddLevelList":null},{"id":"e3","name":"아침 햇살이 가득한 보물","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1403_Ultra","params":null,"skillAddLevelList":{"140301":1,"140303":2}},{"id":"e4","name":"마음이 통하는 평안","desc":"[신의 계시] 지속 시간 동안, 모든 아군이 피해를 가할 시 목표의 방어력을 <unbreak>#1[i]%</unbreak> 무시한다","icon":"SkillIcon_1403_Rank4","params":[0.18],"skillAddLevelList":null},{"id":"e5","name":"기적을 여는 시계","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1403_BP","params":null,"skillAddLevelList":{"140302":2,"140304":2}},{"id":"e6","name":"별과 달이 가득한 내일","desc":"트리비가 필살기 발동 후, 모든 적에게 특성의 <u>추가 공격</u>을 발동한다. 특성의 <u>추가 공격</u>이 가하는 피해가 <unbreak>#1[i]%</unbreak> 증가한다","icon":"SkillIcon_1403_Rank6","params":[7.29],"skillAddLevelList":null}]',
