    '[{"id":"1409101","name":"미소 짓는 먹구름","desc":"히아킨과 이카의 치명타 확률이 <unbreak>#1[i]%</unbreak> 증가한다. 현재 HP가 자신의 HP 최대치의 <unbreak>#2[i]%</unbreak> 이하인 아군에게 치유 제공 시, 히아킨과 이카의 치유량이 <unbreak>#3[i]%</unbreak> 증가한다","icon":"SkillIcon_1409_SkillTree1","params":{"1":[1],"2":[0.5],"3":[0.25]},"unlockAscension":2},{"id":"1409102","name":"부드러운 뇌우","desc":"히아킨의 효과 저항이 <unbreak>#1[i]%</unbreak> 증가한다. 전투 스킬과 필살기 발동 시 모든 아군의 <u>디버프 효과</u>를 <unbreak>#2[i]</unbreak>개 해제한다","icon":"SkillIcon_1409_SkillTree2","params":{"1":[0.5],"2":[1]},"unlockAscension":4},{"id":"1409103","name":"잔잔해진 폭풍","desc":"히아킨의 속도가 <unbreak>#1[i]</unbreak>보다 높을 시 히아킨과 이카의 HP 최대치가 <unbreak>#2[i]%</unbreak> 증가하고, 이후 속도가 <unbreak>#3[i]</unbreak>pt 초과할 때마다 히아킨과 이카가 제공하는 치유량이 <unbreak>#4[i]%</unbreak> 증가한다. 초과한 속도는 최대 <unbreak>#5[i]</unbreak>pt까지 계산된다","icon":"SkillIcon_1409_SkillTree3","params":{"1":[200],"2":[0.2],"3":[1],"4":[0.01],"5":[200]},"unlockAscension":6}]',
    '[{"id":"1409201","stat":"spd","value":2,"parentMajor":null,"unlockAscension":0},{"id":"1409202","stat":"effectRes","value":0.04,"parentMajor":null,"unlockAscension":2},{"id":"1409203","stat":"spd","value":2,"parentMajor":null,"unlockAscension":3},{"id":"1409204","stat":"hpPct","value":0.04,"parentMajor":"1409101","unlockAscension":3},{"id":"1409205","stat":"spd","value":3,"parentMajor":"1409101","unlockAscension":4},{"id":"1409206","stat":"effectRes","value":0.06,"parentMajor":"1409102","unlockAscension":5},{"id":"1409207","stat":"spd","value":3,"parentMajor":"1409102","unlockAscension":5},{"id":"1409208","stat":"hpPct","value":0.06,"parentMajor":"1409103","unlockAscension":6},{"id":"1409209","stat":"effectRes","value":0.08,"parentMajor":"1409103","unlockAscension":6},{"id":"1409210","stat":"spd","value":4,"parentMajor":"1409103","unlockAscension":6}]',
    '[{"id":"e1","name":"어두운 밤의 촛불을 지키며","desc":"히아킨이 [비 온 뒤 맑음] 상태일 시 모든 아군의 HP 최대치가 추가로 <unbreak>#1[i]%</unbreak> 증가하고, 공격 발동 후 즉시 히아킨 HP 최대치의 <unbreak>#2[i]%</unbreak>만큼 HP를 회복한다","icon":"SkillIcon_1409_Rank1","params":[0.5,0.08],"skillAddLevelList":null},{"id":"e2","name":"제 정원에 앉았다 가세요","desc":"아군의 HP가 감소하면 속도가 <unbreak>#1[i]%</unbreak> 증가한다, 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_1409_Rank2","params":[0.3,2],"skillAddLevelList":null},{"id":"e3","name":"출발! 태양을 향한 모험","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>. 기억 정령 스킬 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1409_Ultra","params":null,"skillAddLevelList":{"140901":1,"140903":2,"1140901":1}},{"id":"e4","name":"햇빛 호박을 그대에게","desc":"행적 [잔잔해진 폭풍]이 강화된다. 속도가 <unbreak>#1[i]</unbreak>pt 초과할 때마다 히아킨과 이카의 치명타 피해가 추가로 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1409_Rank4","params":[1,0.02],"skillAddLevelList":null},{"id":"e5","name":"바다의 뒷면에 비치는 붉은 노을","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 기억 정령 특성 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_1409_BP","params":null,"skillAddLevelList":{"140902":2,"140904":2,"1140903":1,"1140905":1,"1140906":1}},{"id":"e6","name":"하늘이… 나의 기도에 응답하리","desc":"이카가 기억 정령 스킬을 발동하고 초기화되는 누적 치유 수치가 <unbreak>#1[i]%</unbreak>로 변경된다. 이카가 필드에 있을 시 모든 아군의 모든 속성 <u>저항 관통</u>이 <unbreak>#2[i]%</unbreak> 증가한다","icon":"SkillIcon_1409_Rank6","params":[0.12,0.2],"skillAddLevelList":null}]',
    '[]'
);

