2,2,2,2,2,2,2],"3":[0.3,0.33,0.36,0.39,0.42,0.45,0.4875,0.525,0.5625,0.6,0.63,0.66,0.69,0.72,0.75],"4":[0.15,0.165,0.18,0.195,0.21,0.225,0.24375,0.2625,0.28125,0.3,0.315,0.33,0.345,0.36,0.375]},"desc":"<u>기억 정령 「긴 밤」을 소환</u>하고, 이후 기억 정령 「긴 밤」이 모든 적에게 「긴 밤」 HP 최대치의 <color=#f29e38ff><unbreak>#1[i]%</unbreak></color>만큼 얼음 속성 피해를 가하며, 에버나이트가 [가장 어두운 수수께끼] 상태에 진입한다. 해당 상태 동안 모든 적이 받는 피해가 <color=#f29e38ff><unbreak>#4[i]%</unbreak></color> 증가하고, 에버나이트와 기억 정령 「긴 밤」이 가하는 피해가 <color=#f29e38ff><unbreak>#3[i]%</unbreak></color> 증가하며, <u>제어류 디버프 상태</u>에 면역된다. [가장 어두운 수수께끼]의 충전을 <unbreak>#2[i]</unbreak>pt 획득하며, 기억 정령 「긴 밤」이 [이슬처럼 사라지는 미몽]을 발동하면 1pt 소모한다. 에버나이트의 턴 시작 시, 남은 충전이 없으면 [가장 어두운 수수께끼] 상태가 종료된다","tag":"범위 공격","maxLevel":10,"skillId":"141303"},{"id":"talent","levelKey":"talent","name":"오늘 밤, 나와 함께","formula":"evernight.talent","icon":"SkillIcon_1413_Passive","params":{"1":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2],"2":[0.3,0.33,0.36,0.39,0.42,0.45,0.4875,0.525,0.5625,0.6,0.63,0.66,0.69,0.72,0.75],"3":[2,2,2,2,2,2,2,2,2,2,2,2,2,2,2],"4":[160,160,160,160,160,160,160,160,160,160,160,160,160,160,160],"5":[0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5,0.5],"6":[16,16,16,16,16,16,16,16,16,16,16,16,16,16,16],"7":[0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05,0.05]},"desc":"전투 진입 시 <u>기억 정령 「긴 밤」을 소환</u>한다. 기억 정령 「긴 밤」의 기본 속도는 <unbreak>#4[i]</unbreak>pt이며, HP 최대치는 에버나이트의 <unbreak>#5[i]%</unbreak>다. 에버나이트 또는 기억 정령 「긴 밤」의 HP가 감소할 때마다 자신과 기억 정령 「긴 밤」의 치명타 피해가 <unbreak>#3[i]</unbreak>턴 동안 <color=#f29e38ff><unbreak>#2[i]%</unbreak></color> 증가하고, [기억 물질]을 <unbreak>#1[i]</unbreak>pt 획득한다. 해당 효과는 각 목표가 피격될 때마다 최대 1회 발동한다.\\n에버나이트가 보유한 [기억 물질]이 <unbreak>#6[i]</unbreak>pt 이상일 시 <u>제어류 디버프 상태</u>를 해제하고 이에 면역되며, 기억 정령 「긴 밤」이 필드에 있으면 즉시 대상을 행동하게 한다. 즉시 행동 효과는 기억 정령 「긴 밤」이 [이슬처럼 사라지는 미몽]을 발동한 후에 다시 발동할 수 있다","tag":"강화","maxLevel":10,"skillId":"141304"},{"id":"technique","levelKey":"technique","name":"차가운 비가 내리기를","formula":"evernight.technique","icon":"SkillIcon_1413_Maze","params":{"1":[1],"2":[1]},"desc":"비술을 사용하면 다음 전투 시작 시 전투 스킬과 동일한 모든 아군 기억 정령 치명타 피해 증가 효과를 획득하고, [기억 물질]을 <unbreak>#1[i]</unbreak>pt 획득한다","tag":"서포트","maxLevel":1,"skillId":"141307"}]',
