    '[{"id":"e1","name":"#인기_검색어:그녀는_누구?","desc":"아하 타임 종료 시 <u>웃음 포인트</u>를 <unbreak>#1[i]</unbreak>pt 획득한다. 현재 보유한 <u>웃음 포인트</u> 1pt당 모든 아군의 모든 속성 <u>저항 관통</u>이 <unbreak>#2[f1]%</unbreak> 증가하며, 최대 <unbreak>#3[i]%</unbreak> 증가한다","icon":"SkillIcon_1501_Rank1","params":[5,0.015,0.15],"skillAddLevelList":null},{"id":"e2","name":"#시청자의_눈은_정확하다","desc":"아하 타임 종료 시 스파키는 <u>보너스 턴</u> 1개와 [킬링 포인트] <unbreak>#1[i]</unbreak>개를 획득한다. [킬링 포인트]를 1개 소모할 때마다 자신의 치명타 피해가 <unbreak>#2[i]%</unbreak> 증가한다, 지속 시간: <unbreak>#3[i]</unbreak>턴, 최대 중첩수: <unbreak>#4[i]</unbreak>스택","icon":"SkillIcon_1501_Rank2","params":[2,0.1,2,4],"skillAddLevelList":null},{"id":"e3","name":"#눌러봐:두근두근_링크","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>. 환락 스킬 레벨+1, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1501_BP","params":null,"skillAddLevelList":{"150101":1,"150102":2,"150108":1,"150109":2,"150120":1}},{"id":"e4","name":"#시선_강탈!표정관리_만렙","desc":"필살기 발동 시 추가로 <u>웃음 포인트</u>를 <unbreak>#1[i]</unbreak>pt 획득하고, 자신의 환락도를 <unbreak>#2[i]%</unbreak> 증가시킨다, 지속 시간: <unbreak>#3[i]</unbreak>턴","icon":"SkillIcon_1501_Rank4","params":[5,0.36,3],"skillAddLevelList":null},{"id":"e5","name":"#망가진_세계는_파키가_수선중","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 환락 스킬 레벨+1, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_1501_Ultra","params":null,"skillAddLevelList":{"150103":2,"150104":2,"150120":1}},{"id":"e6","name":"#짜잔_곧_절판될_나","desc":"모든 속성 <u>저항 관통</u>이 <unbreak>#3[i]%</unbreak> 증가한다. 환락 스킬은 <u>웃음 포인트</u>가 <unbreak>#1[i]</unbreak>pt 집계될 때마다 가하는 피해 횟수가 추가로 1회 증가하며, 최대 <unbreak>#2[i]</unbreak>회까지 증가한다","icon":"SkillIcon_1501_Rank6","params":[1,40,0.2],"skillAddLevelList":null}]',
