    '[{"id":"e1","name":"최고의 관중석","desc":"처음으로 전투 스킬을 발동한 후 즉시 전투 스킬 포인트를 <unbreak>#1[i]</unbreak>pt 회복한다","icon":"SkillIcon_8005_Rank1","params":[1],"skillAddLevelList":null},{"id":"e2","name":"탈옥의 레인보우 스텝","desc":"전투 시작 시 개척자의 에너지 회복효율이 <unbreak>#1[i]%</unbreak> 증가한다. 지속 시간: <unbreak>#2[i]</unbreak>턴","icon":"SkillIcon_8005_Rank2","params":[0.25,3],"skillAddLevelList":null},{"id":"e3","name":"쉼표의 요양원","desc":"전투 스킬 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 특성 레벨+2, 최대 Lv.<unbreak>15</unbreak>","icon":"SkillIcon_8005_BP","params":null,"skillAddLevelList":{"800602":2,"800604":2}},{"id":"e4","name":"비둘기를 감춘 모자","desc":"개척자가 필드에 있을 시, 자신을 제외한 동료의 격파 특수효과를 개척자의 격파 특수효과의 <unbreak>#1[i]%</unbreak>만큼 증가시킨다","icon":"SkillIcon_8005_Rank4","params":[0.15],"skillAddLevelList":null},{"id":"e5","name":"오래된 리듬을 간직한 시","desc":"필살기 레벨+2, 최대 Lv.<unbreak>15</unbreak>. 일반 공격 레벨+1, 최대 Lv.<unbreak>10</unbreak>","icon":"SkillIcon_8005_Ultra","params":null,"skillAddLevelList":{"800601":1,"800603":2}},{"id":"e6","name":"내일은 스포트라이트 아래서 휴식을","desc":"전투 스킬의 피해 횟수가 추가로 <unbreak>#1[i]</unbreak>회 증가한다","icon":"SkillIcon_8005_Rank6","params":[2],"skillAddLevelList":null}]',
